// Auto-generated FC+activation wrapper
// Workload: K=128, N=64
// Crossbar: 1024x128
// Conversion: acam, DPE DATA_WIDTH: 40
// Mode: streaming (2-DPE ping-pong)
// Tiling: V=1, H=1, DPEs=2
// ACAM eligible (V=1 + ACAM): yes
// CLB activation LUT: no (ACAM)
// Generated by gen_gemv_wrappers.py --fc --streaming

// =====================================================
// fc_top — top-level module
// =====================================================
// Streaming FC wrapper (K=128, N=64)
//   Two-DPE ping-pong: DPE_A loads while DPE_B computes/outputs.
//   PACKED_K=26, PACKED_N=13, EPW=5
//   Steady-state throughput: 26 cycles per inference.
//   No SRAM input buffer; valid → DPE w_buf_en directly.

module fc_top_qkv_streaming #(
    parameter DATA_WIDTH = 40
)(
    input  wire                  clk,
    input  wire                  rst,
    input  wire                  valid,
    input  wire                  ready_n,
    input  wire [DATA_WIDTH-1:0] data_in,
    output wire [DATA_WIDTH-1:0] data_out,
    output wire                  ready,
    output wire                  valid_n
);

    localparam K          = 128;
    localparam N_OUT      = 64;
    localparam EPW        = 5;
    localparam PACKED_K   = 26;
    localparam PACKED_N   = 13;

    // ─── Per-DPE wires ──────────────────────────────────────
    wire [DATA_WIDTH-1:0] dpe_a_data_out;
    wire dpe_a_done;
    wire dpe_a_reg_full;
    wire dpe_a_msb_sa_ready;
    wire dpe_a_shift_add_done;
    wire dpe_a_shift_add_bypass_ctrl;
    reg  dpe_a_w_buf_en;
    wire [DATA_WIDTH-1:0] dpe_b_data_out;
    wire dpe_b_done;
    wire dpe_b_reg_full;
    wire dpe_b_msb_sa_ready;
    wire dpe_b_shift_add_done;
    wire dpe_b_shift_add_bypass_ctrl;
    reg  dpe_b_w_buf_en;

    // ─── Streaming controller (load-side) ───────────────────
    // load_active=0 → strobes go to DPE_A; =1 → DPE_B.
    // load_count counts strobes within the current inference.
    reg load_active;
    reg [5-1:0] load_count;
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            load_active <= 1'b0;
            load_count  <= 0;
            dpe_a_w_buf_en <= 1'b0;
            dpe_b_w_buf_en <= 1'b0;
        end else begin
            // Default: deassert both strobes
            dpe_a_w_buf_en <= 1'b0;
            dpe_b_w_buf_en <= 1'b0;
            if (valid) begin
                if (load_active == 1'b0) dpe_a_w_buf_en <= 1'b1;
                else                     dpe_b_w_buf_en <= 1'b1;
                if (load_count + 1 == PACKED_K) begin
                    load_count  <= 0;
                    load_active <= ~load_active;
                end else begin
                    load_count <= load_count + 1;
                end
            end
        end
    end

    // ─── DPE A and B instances ──────────────────────────────
    // KERNEL_WIDTH is the unpacked element count (K). NUM_COLS is N_OUT.
    // nl_dpe_control is tied to 2'b11 (always-fire after reg_full).
    // shift_add_control / load_input_reg / load_output_reg / shift_add_bypass:
    // unused by behavioral DPE primitive — tie to 0.
    dpe #(.KERNEL_WIDTH(K), .NUM_COLS(N_OUT)) dpe_a_inst (
        .clk(clk), .reset(rst),
        .data_in(data_in),
        .nl_dpe_control(2'b11),
        .shift_add_control(1'b0),
        .w_buf_en(dpe_a_w_buf_en),
        .shift_add_bypass(1'b0),
        .load_output_reg(1'b0),
        .load_input_reg(1'b0),
        .MSB_SA_Ready(dpe_a_msb_sa_ready),
        .data_out(dpe_a_data_out),
        .dpe_done(dpe_a_done),
        .reg_full(dpe_a_reg_full),
        .shift_add_done(dpe_a_shift_add_done),
        .shift_add_bypass_ctrl(dpe_a_shift_add_bypass_ctrl)
    );
    dpe #(.KERNEL_WIDTH(K), .NUM_COLS(N_OUT)) dpe_b_inst (
        .clk(clk), .reset(rst),
        .data_in(data_in),
        .nl_dpe_control(2'b11),
        .shift_add_control(1'b0),
        .w_buf_en(dpe_b_w_buf_en),
        .shift_add_bypass(1'b0),
        .load_output_reg(1'b0),
        .load_input_reg(1'b0),
        .MSB_SA_Ready(dpe_b_msb_sa_ready),
        .data_out(dpe_b_data_out),
        .dpe_done(dpe_b_done),
        .reg_full(dpe_b_reg_full),
        .shift_add_done(dpe_b_shift_add_done),
        .shift_add_bypass_ctrl(dpe_b_shift_add_bypass_ctrl)
    );

    // ─── Output mux + valid_n ───────────────────────────────
    // dpe_*_done pulses high during S_OUTPUT (PACKED_N cycles).
    // In steady state only one DPE is in S_OUTPUT at a time.
    assign valid_n  = dpe_a_done | dpe_b_done;
    assign data_out = dpe_a_done ? dpe_a_data_out :
                      dpe_b_done ? dpe_b_data_out : {DATA_WIDTH{1'b0}};

    // ready: always accept inputs — the FSM dispatches to the
    // currently-loading DPE; if both DPEs are full, an external
    // back-pressure could be added, but the V2 TB drives valid_x
    // unconditionally and the ping-pong absorbs the stream.
    assign ready = ~rst;

endmodule
